// Extract error information
const error = $input.item.json.error || {};
const workflow = $input.item.json.workflow || {};
const execution = $input.item.json.execution || {};

// Format error message
const errorMessage = {
  workflow: workflow.name || 'Unknown',
  workflowId: workflow.id || 'Unknown',
  executionId: execution.id || 'Unknown',
  error: {
    message: error.message || 'Unknown error',
    stack: error.stack || '',
    name: error.name || 'Error'
  },
  timestamp: new Date().toISOString(),
  node: $input.item.json.node?.name || 'Unknown',
  nodeId: $input.item.json.node?.id || 'Unknown'
};

return errorMessage;

